import { PaymentMethod } from '@domain/paymentMethod';
import { useCallback } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { FormAddressControl } from '../../../AddressControl';
import { Button } from '../../../Button';
import { FormGroup } from '../../../FormGroup';
import { FormMaskedInputControl } from '../../../MaskedInputControl';
import { PaymentMethodDisplay } from '../../../PaymentMethodDisplay';
import { IPaymentMethodForm } from '../../types';

export type ExpirationDateFormProps = {
  additionalAction?: React.ReactNode;
  paymentMethod: PaymentMethod;
};

export const ExpirationDateForm = ({
  additionalAction,
  paymentMethod,
}: ExpirationDateFormProps) => {
  const { t } = useTranslation('finance', { keyPrefix: 'commitments.paymentMethodForm' });
  const { setValue } = useFormContext<IPaymentMethodForm>();

  const onClickNew = useCallback(() => {
    setValue('isUpdatingMethod', false);
  }, [setValue]);

  return (
    <>
      <FormGroup title={t('headings.creditCardInformation')}>
        <div className="flex flex-col items-stretch p-4">
          <div>
            <div className="flex flex-1">
              {/**
               * Union type for payment method apparently breaks down
               * @ts-ignore */}
              <PaymentMethodDisplay {...paymentMethod} showExpiration={false} />
            </div>
            <Button onClick={onClickNew}>{t('buttons.changePaymentMethod')}</Button>
          </div>
          <FormMaskedInputControl
            autoComplete="cc-exp"
            data-analytics-ignore
            isRequired
            label={t('expirationDate.label')}
            name="expDate"
            type="expiry"
          />
          {additionalAction}
        </div>
      </FormGroup>
      <FormGroup title={t('headings.billingAddress')}>
        <FormAddressControl />
      </FormGroup>
    </>
  );
};

